INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (3, 2, 433, 4.0, '堪称教科书级别的作品，后人很难超越了，个人很喜欢', '2025-12-29 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (4, 3, 82, 4.0, '诗人这功底没话说，每一个字都恰到好处', '2025-05-14 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (5, 3, 876, 3.0, '《鸟鸣涧》作为入门级的诗词可以，深入研究就一般了', '2025-07-30 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (6, 3, 239, 3.0, '经典!，特别是''轻舟已过万重山''这句', '2025-04-03 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (7, 4, 147, 3.0, '这首诗的意象我不太理解，推荐阅读', '2026-03-02 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (8, 4, 272, 1.0, '可能是我欣赏水平达不到这个层次', '2025-10-28 19:36:32');
INSERT INTO reviews (id, user_id, poem_id, rating, comment, created_at) VALUES (9, 4, 143, 3.0, '总体还行，但总觉得差了点什么', '2025-12-19 19:36:32');
